/* wms-ctmaster-location-sql-oracle.xml - updateLocation */
UPDATE TWORK_MST_LC
   SET CMT = #{cmt}
	 , LCTYPECD = #{lctypecd}
	 , LCHOLDTYPECD = #{lcholdtypecd}
	 , LCSTORGTYPECD = #{lcstorgtypecd}
	 , ICTMPRDIVCD = #{ictmprdivcd}
	 , ICKEYMIXCGYN = #{ickeymixcgyn}
	 , IVATKEYMIXCGYN = #{ivatkeymixcgyn}
	 , FIXYN = #{fixyn}
	 , LCLIMITDIVCD = #{lclimitdivcd}
	 , LCDIVNO = #{lcdivno}
	 , FLOOR = #{floor}
	 , RACKNO = #{rackno}
	 , ROWNO = #{rowno}
	 , TIERNO = #{tierno}
	 , SPLNO = #{splno}
	 , SPLQTYDIVCD = #{splqtydivcd}
	 , ALTMTARNO = #{altmtarno}
	 , ALTMTALENO = #{altmtaleno}
	 , ALEBARCODE = #{alebarcode}
	 , ICARDIVCD = #{icardivcd}
	 , ICPLCMDIVCD = #{icplcmdivcd}
	 , IVCNTRMGMTYN = #{ivcntrmgmtyn}
	 , WIDTH = #{width}
	 , DEPTH = #{depth}
	 , HEIGHT = #{height}
	 , CBMSTARTRNG = #{cbmstartrng}
	 , CBMCLOSRNG = #{cbmclosrng}
	 , UPDATEDATE = #{sysdate}
	 , UPDATEURKEY = #{surkey}
WHERE CTKEY = #{ctkey}
  AND LCKEY = #{lckey}

