mapper.select:
/* wms-ctmaster-location-sql-oracle.xml - selectIfSendLocationList */ SELECT LC.CTKEY , LC.ZNKEY , ZN.ZNNM , LC.ARKEY , AR.ARNM , LC.LCKEY , LC.CBMSTARTRNG , LC.CBMCLOSRNG , #{useyn} AS USEYN , AR.ANSUNGB2BPOCTG , AR.NAMSAB2BPOCTG , AR.BUSANB2BPOCTG , AR.SEJONGB2BPOCTG FROM TWORK_MST_LC LC INNER JOIN TWORK_MST_ZN ZN ON ZN.ZNKEY = LC.ZNKEY INNER JOIN TWORK_MST_AR AR ON AR.ZNKEY = LC.ZNKEY AND AR.ARKEY = LC.ARKEY WHERE LC.CTKEY = #{ctkey}
AND LC.LCKEY IN (
#{item.lckey}
)
AND 1 = 2
